817       Known2 = Known2.intersectWith(Known3);
818     Known = Known.unionWith(Known2);
819   }
820 
821   if (auto *Cmp = dyn_cast<ICmpInst>(Cond))
822     computeKnownBitsFromICmpCond(V, Cmp, Known, SQ, Invert);
